//go:build vectors

package ingest

import (
	"context"
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"time"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
	"github.com/a<HOME>/agentic-rag-mcp/internal/domain"
	"github.com/a<HOME>/agentic-rag-mcp/internal/embedder"
)

// AtomicRebuild creates a new index at a temp path, indexes all files,
// then swaps with the existing index. If the rebuild fails, the existing
// index is preserved.
func AtomicRebuild(
	ctx context.Context,
	indexer *Indexer,
	emb embedder.Embedder,
	secCfg config.SecurityConfig,
	maxChunkSize int,
	dir string,
	scope string,
	kind string,
) (domain.IndexResult, error) {
	start := time.Now()
	var result domain.IndexResult

	// Create temp index
	tempPath := indexer.Path() + ".rebuild." + fmt.Sprintf("%d", time.Now().UnixNano())
	tempIndex, err := CreateTempIndex(tempPath, indexer.Dims())
	if err != nil {
		return result, fmt.Errorf("creating temp index: %w", err)
	}

	// Ensure cleanup on failure
	success := false
	defer func() {
		if !success {
			tempIndex.Close()
			os.RemoveAll(tempPath)
		}
	}()

	// Create a temp indexer to use during rebuild
	tempIndexer := NewIndexerWithIndex(tempIndex, tempPath, indexer.Dims())
	tempPipeline := NewPipeline(tempIndexer, emb, secCfg, maxChunkSize)

	// Walk directory and index all files
	err = filepath.Walk(dir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if ctx.Err() != nil {
			return ctx.Err()
		}

		if info.IsDir() {
			name := info.Name()
			for _, blocked := range secCfg.DirectoryBlocklist {
				if name == blocked {
					return filepath.SkipDir
				}
			}
			return nil
		}

		fr := SecurityFilter(path, info, secCfg)
		if !fr.Allowed {
			return nil
		}

		// Always force when rebuilding
		fileResult, err := tempPipeline.indexFile(ctx, path, scope, kind, true)
		if err != nil {
			slog.Error("rebuild: indexing file", "path", path, "error", err)
			result.Errors++
			result.FileErrors = append(result.FileErrors, domain.IndexFileError{
				Path:    path,
				Message: err.Error(),
			})
			return nil
		}

		result.Indexed += fileResult.Indexed
		result.Chunks += fileResult.Chunks
		result.Details = append(result.Details, fileResult.Details...)
		return nil
	})

	if err != nil {
		return result, fmt.Errorf("rebuild failed, existing index preserved: %w", err)
	}

	// Swap: replace existing index with new one
	newHashes := tempIndexer.IndexedPaths()
	indexer.SwapIndex(tempIndex, newHashes)

	// Remove old index path and rename temp
	oldPath := indexer.Path()
	if oldPath != tempPath {
		// The old bleve index files need to be cleaned up
		// but the swap already closed the old index
		os.RemoveAll(oldPath)
		os.Rename(tempPath, oldPath)
	}

	success = true
	result.Duration = time.Since(start)

	slog.Info("atomic rebuild complete",
		"indexed", result.Indexed,
		"chunks", result.Chunks,
		"duration", result.Duration,
	)

	return result, nil
}
